import React, { useState } from 'react';

export type Item = {
  object_id: string;
  fields: Record<string, any>; // works for Owner, DataType, DataItem, Child
};

type ItemsTableProps = {
  containerId: string;
  items?: Item[];
  error?: string;
};

export const ItemsTable: React.FC<ItemsTableProps> = ({ containerId, items = [], error }) => {
  const [expandedCells, setExpandedCells] = useState<Set<string>>(new Set());

  const toggleCell = (cellId: string) => {
    setExpandedCells(prev => {
      const copy = new Set(prev);
      if (copy.has(cellId)) copy.delete(cellId);
      else copy.add(cellId);
      return copy;
    });
  };

  // Dynamically determine table columns from the first item
  const columns = items.length > 0 ? Object.keys(items[0].fields) : [];

  return (
    <div style={{ padding: 20 }}>
      <h2>Items in Container: {containerId}</h2>

      {error && <div style={{ color: 'red', marginBottom: 10 }}>Error: {error}</div>}

      {items.length > 0 ? (
        <table style={{ width: '100%', borderCollapse: 'collapse', tableLayout: 'fixed' }}>
          <thead>
            <tr>
              <th>Object ID</th>
              {columns.map(col => (
                <th key={col}>{col}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {items.map(item => (
              <tr key={item.object_id}>
                <td style={{ border: '1px solid #ddd', padding: '10px' }}>{item.object_id}</td>
                {columns.map((col, idx) => {
                  const cellId = `${item.object_id}-${idx}`;
                  const isExpanded = expandedCells.has(cellId);
                  const value = item.fields[col] ?? '-';
                  return (
                    <td key={idx} style={{ border: '1px solid #ddd', padding: '10px' }}>
                      <div
                        style={{
                          maxHeight: isExpanded ? 'none' : '50px',
                          overflow: 'hidden',
                          cursor: 'pointer',
                          position: 'relative',
                          paddingRight: '20px',
                        }}
                        onClick={() => toggleCell(cellId)}
                      >
                        {typeof value === 'object'
                          ? JSON.stringify(value, null, 2)
                          : value.toString()}
                        <span
                          style={{
                            position: 'absolute',
                            right: 5,
                            bottom: 5,
                            fontSize: 12,
                            color: '#555',
                          }}
                        >
                          {isExpanded ? '▲' : '▼'}
                        </span>
                      </div>
                    </td>
                  );
                })}
              </tr>
            ))}
          </tbody>
        </table>
      ) : (
        <p>No items found in this container.</p>
      )}
    </div>
  );
};
